        /* FUSED: save x0..x1 to s-regs, spill x2..x7 */
        s0_re = x0_re; s0_im = x0_im;
        s1_re = x1_re; s1_im = x1_im;
        _mm512_store_pd(&spill_re[58*8],x2_re);
        _mm512_store_pd(&spill_im[58*8],x2_im);
        _mm512_store_pd(&spill_re[59*8],x3_re);
        _mm512_store_pd(&spill_im[59*8],x3_im);
        _mm512_store_pd(&spill_re[60*8],x4_re);
        _mm512_store_pd(&spill_im[60*8],x4_im);
        _mm512_store_pd(&spill_re[61*8],x5_re);
        _mm512_store_pd(&spill_im[61*8],x5_im);
        _mm512_store_pd(&spill_re[62*8],x6_re);
        _mm512_store_pd(&spill_im[62*8],x6_im);
        _mm512_store_pd(&spill_re[63*8],x7_re);
        _mm512_store_pd(&spill_im[63*8],x7_im);

        /* PASS 2 */

        /* column k1=0 */
        x0_re = _mm512_load_pd(&spill_re[0*8]);
        x0_im = _mm512_load_pd(&spill_im[0*8]);
        x1_re = _mm512_load_pd(&spill_re[8*8]);
        x1_im = _mm512_load_pd(&spill_im[8*8]);
        x2_re = _mm512_load_pd(&spill_re[16*8]);
        x2_im = _mm512_load_pd(&spill_im[16*8]);
        x3_re = _mm512_load_pd(&spill_re[24*8]);
        x3_im = _mm512_load_pd(&spill_im[24*8]);
        x4_re = _mm512_load_pd(&spill_re[32*8]);
        x4_im = _mm512_load_pd(&spill_im[32*8]);
        x5_re = _mm512_load_pd(&spill_re[40*8]);
        x5_im = _mm512_load_pd(&spill_im[40*8]);
