        /* sub-FFT n2=7 */
        x0_re = LD(&rio_re[m+7*ios]);
        x0_im = LD(&rio_im[m+7*ios]);
        x1_re = LD(&rio_re[m+15*ios]);
        x1_im = LD(&rio_im[m+15*ios]);
