        { __m512d wr = _mm512_load_pd(&W_re[55*me+m]);
          __m512d wi = _mm512_load_pd(&W_im[55*me+m]);
          __m512d tr = x7_re;
          x7_re = _mm512_fmsub_pd(x7_re,wr,_mm512_mul_pd(x7_im,wi));
          x7_im = _mm512_fmadd_pd(tr,wi,_mm512_mul_pd(x7_im,wr)); }

        ST(&rio_re[m+0*ios],x0_re);
        ST(&rio_im[m+0*ios],x0_im);
        ST(&rio_re[m+8*ios],x1_re);
        ST(&rio_im[m+8*ios],x1_im);
        ST(&rio_re[m+16*ios],x2_re);
        ST(&rio_im[m+16*ios],x2_im);
        ST(&rio_re[m+24*ios],x3_re);
        ST(&rio_im[m+24*ios],x3_im);
        ST(&rio_re[m+32*ios],x4_re);
        ST(&rio_im[m+32*ios],x4_im);
        ST(&rio_re[m+40*ios],x5_re);
        ST(&rio_im[m+40*ios],x5_im);
        ST(&rio_re[m+48*ios],x6_re);
        ST(&rio_im[m+48*ios],x6_im);
        ST(&rio_re[m+56*ios],x7_re);
        ST(&rio_im[m+56*ios],x7_im);

        /* column k1=1 */
        x0_re = _mm512_load_pd(&spill_re[1*8]);
        x0_im = _mm512_load_pd(&spill_im[1*8]);
        x1_re = _mm512_load_pd(&spill_re[9*8]);
        x1_im = _mm512_load_pd(&spill_im[9*8]);
        x2_re = _mm512_load_pd(&spill_re[17*8]);
        x2_im = _mm512_load_pd(&spill_im[17*8]);
        x3_re = _mm512_load_pd(&spill_re[25*8]);
        x3_im = _mm512_load_pd(&spill_im[25*8]);
